import React from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';


document.addEventListener('DOMContentLoaded', function () {
    console.log("Logger init");

    fetch('http://localhost:3001/events')
      .then(response => response.json())
      .then(events => {
        console.log("Fetched events:", events);

        const validEvents = events.filter(event => {
          const isValid = event.id && event.title && event.start;
          if (!isValid) {
            console.log("Invalid event detected:", event);
          }
          return isValid;
        });

        console.log("Filtered valid events:", validEvents);

        const calendarEvents = validEvents.map(event => ({
          id: event.id,
          title: event.title,
          start: event.start,
          description: event.description,
          venue: event.venue,
          url: event.event_link,
          flyerImage: event.flyer_image,
        }));

        console.log("Mapped calendar events (for FullCalendar):", calendarEvents);

        const calendarEl = document.getElementById('calendar');
        const calendar = new FullCalendar.Calendar(calendarEl, {
          plugins: [dayGridPlugin],
          initialView: 'dayGridMonth',
          events: calendarEvents,
          eventClick: function (info) {
            info.jsEvent.preventDefault();
            if (info.event.url) {
              window.open(info.event.url);
            }
          }
        });

        calendar.render();
      })
      .catch(error => {
        console.error("Error fetching events:", error);
      });
  });
